CREATE TABLE public.date_places (
  id text PRIMARY KEY,
  name text NOT NULL,
  category text NOT NULL,
  area text NOT NULL,
  address text NOT NULL,
  lat numeric(9,6) NOT NULL,
  lng numeric(9,6) NOT NULL,
  rating numeric(2,1) NOT NULL DEFAULT 4.0,
  review_count integer NOT NULL DEFAULT 0,
  price_range text,
  menu_examples text[] NOT NULL DEFAULT '{}',
  mood text,
  is_after boolean NOT NULL DEFAULT false,
  reason text,
  image_query text,
  sort_weight integer NOT NULL DEFAULT 0,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

GRANT SELECT ON public.date_places TO anon, authenticated;
GRANT ALL ON public.date_places TO service_role;

ALTER TABLE public.date_places ENABLE ROW LEVEL SECURITY;

CREATE POLICY "date_places_public_read" ON public.date_places
  FOR SELECT TO anon, authenticated USING (true);

CREATE TRIGGER set_date_places_updated_at
  BEFORE UPDATE ON public.date_places
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

CREATE INDEX date_places_area_idx ON public.date_places (area);

ON CONFLICT (id) DO NOTHING;